const themes = ['Food spotlight','Atmosphere / weekend vibe','Bar & drinks','Community / local feel','Three-kitchen heritage','Weekly special or event'];
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const week = Math.floor((now - startOfYear) / (7*24*60*60*1000));
const weekTheme = themes[week % 6];

const overrideItems = $('Check Theme Override').all();
const firstItem = overrideItems.length > 0 ? overrideItems[0].json : {};
const theme = (firstItem && firstItem.custom_theme) ? firstItem.custom_theme : weekTheme;

const dayOfWeek = now.toLocaleDateString('en-GB', { weekday: 'long', timeZone: 'Europe/London' });
const chatIds = ['1342891001', '5765665250', '5930338959'];
return chatIds.map(chatId => ({ json: { theme, dayOfWeek, chatId } }));
